INSERT INTO `tblTrait` (`name`, `class`, `type`, `isUnique`, `rankType`, `traitGroup`, `cost`, `income`, `evolution`, `staffRequirements`, `description`) VALUES
  ('Verarmde of recent verheven adel', 'upper class', 'status', 1, 'range_signed', 'Adeldom', 0, 50, 0.15, 0, 'Je stamt af van verarmde of een recent verheven adellijke familie met weinig geld en macht. De hoogste titel in jouw familie is die van baron of barones. Je familie heeft geen investeringen of grote eigendommen en kan je alleen maar een appartement geven om in te wonen. Het vermogen van je familie wordt geschat tussen de 30 000Fr en de 500 000Fr.'),
  ('Landelijke adel', 'upper class', 'status', 1, 'range_signed', 'Adeldom', 1, 160, 0.15, 0, 'Je stamt af van landelijke adel die op lokaal vlak invloed heeft. De baron of barones staat aan het hoofd van de familie en zijn er nog een paar ridders ook. Jouw familie kan één of twee landerijen hebben, een paar stadswoningen of herenhuizen of misschien zelfs een klein kasteel waar ze heel trots op zijn en waar het hoofd van de familie in woont. Jouw familie kan ook enkele economische belangen in lokale ondernemingen hebben. Het vermogen van je familie wordt geschat tussen de 240 000Fr en de 3 500 000Fr.'),
  ('Nationale adel', 'upper class', 'status', 1, 'range_signed', 'Adeldom', 2, 320, 0.15, 1, 'Jouw familie is een belangrijke en welbekende speler op nationaal vlak. De familie wordt geleid door een burggraaf en burggravin en er zijn mogelijks nog wat andere titels beschikbaar. Jouw familie bezit enkele landerijen, herenhuizen en misschien een kasteel of stadspaleis. Jouw familie kan op nationaal vlak behoorlijk wat economische macht binnen een bepaalde nijverheid bezitten. Het vermogen van je familie wordt geschat tussen de 1 500 000Fr en de 25 000 000Fr.'),
  ('Oud en prestigieus geslacht', 'upper class', 'status', 1, 'range_signed', 'Adeldom', 3, 590, 0.15, 2, 'Je stamt af van een zeer oud en prestigieus geslacht dat een belangrijke speler is in de economie en/of politiek van het land. Aan het hoofd van de familie staat een graaf of gravin en er zijn vele andere titels binnen jouw familie te rapen. Ze behoren niet tot de rijkste families van het land, maar ze komen in de buurt. Waarschijnlijk hebben ze meerdere economische belangen in binnen- en buitenland en bezitten ze meerdere landerijen, herenhuizen en enkele kastelen of stadspaleizen. Het vermogen van je familie wordt geschat tussen de 15 000 000Fr en de 200 000 000Fr.'),
  ('Groot Europees geslacht', 'upper class', 'status', 1, 'range_signed', 'Adeldom', 4, 1050, 0.15, 3, 'Je bent een telg van één der grote adellijke geslachten van Europa. Opgepast, want elke blaam op het smetteloze blazoen van jouw familie zal heel streng bestraft worden! Alle adellijke titels kunnen voorkomen in jouw familie. De titel van graaf of gravin wordt in deze familie automatisch omgezet tot markies of markiezin. De rijkdom van jouw familie is fenomenaal en haast onuitputtelijk. De familie bezit uitgestrekte landerijen, stadswijken, herenhuizen en meerdere kastelen en stadspaleizen. Het vermogen van je familie wordt geschat tussen de 100 000 000Fr en de 1 500 000 000Fr.'),
  ('Ongetitelde adel', 'upper class', 'status', 1, 'singular', 'Adellijke titel', 0, NULL, NULL, 0, 'Predicaat is jonkvrouw of jonkheer, tenzij je adeldom 4 genomen hebt. Dan is jouw predicaat prins of prinses.'),
  ('Adellijke titel', 'upper class', 'status', 1, 'singular', 'Adellijke titel', 1, NULL, NULL, 1, 'Je bezit een adellijke titel die beschikbaar is binnen je familie.'),
  ('Familiehoofd', 'upper class', 'status', 1, 'singular', 'Adellijke titel', 2, NULL, NULL, 2, 'Je draagt de hoogste adellijke titel binnen jouw familie. Het is jouw plicht om de rijkdommen en de macht van jouw familie goed te beheren. De goede naam van een familie is alles, en jij bent er de voorvechter en behouder van. Als jij jouw plichten verzuimt of je maakt er een boeltje van, dan zal jouw familie daar op reageren.'),
  ('Belangrijke aandeelhouder in een kleine onderneming of expeditie', 'upper class', 'status', 0, 'range_signed', 'Economie', 2, NULL, NULL, 0, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 900Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Vastgoed in een arbeiderswijk', 'upper class', 'status', 0, 'range_signed', 'Economie', 3, 160, 0.05, 0, 'Je bezit vastgoed in een arbeiderswijk van de stad. Alle huurgelden worden integraal op jouw rekening gestort. Dit is een heel veilige belegging.'),
  ('Hoofdaandeelhouder in een kleine onderneming of expeditie', 'upper class', 'status', 0, 'range_signed', 'Economie', 3, NULL, NULL, 0, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 1500Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Spaarder', 'upper class', 'status', 0, 'range_signed', 'Economie', 3, NULL, NULL, 0, 'Bij de start van het spel begin je met een bedrag op je spaarboekje dat gelijk is aan x150 je inkomsten, i.p.v. x10. Tussen 2 evenementen krijg je x4 je netto inkomsten i.p.v. x3.'),
  ('Belangrijke aandeelhouder in een grote onderneming of expeditie', 'upper class', 'status', 0, 'range_signed', 'Economie', 4, NULL, NULL, 1, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 3000Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Grootgrondbezitter', 'upper class', 'status', 0, 'range_signed', 'Economie', 5, 360, 0.05, 0, 'Je bezit uitgestrekte landerijen en bossen vol met wild. Boeren huren het land van jou om te bewerken. In de wouden heb jij de jachtrechten. Dit is een heel veilige belegging.'),
  ('Hoofdaandeelhouder in een grote onderneming of expeditie', 'upper class', 'status', 0, 'range_signed', 'Economie', 5, NULL, NULL, 2, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 10 000Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Leopoldsorde', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 2, -125, NULL, 0, 'Belgische kroonorde. Lidmaatschap van deze orde is zeer prestigieus. Alleen de absolute elite, of zij die een uitzonderlijke verdienste aan de maatschappij hebben geleverd, worden toegelaten. Deze lobbygroep kan invloed uitoefenen op politiek en militair vlak. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een hogere rang te bekleden binnen het gezelschap.'),
  ('Exclusieve loge in de opera', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 2, -100, NULL, 0, 'Deze loge wordt altijd voor jou gereserveerd. Het is de ideale plek om gasten mee naar toe te nemen voor informele gesprekken en eerste ontmoetingen met bewoners van de stad.'),
  ('Vrijmetselarij', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 2, -75, NULL, 0, 'Een geheimzinnig gezelschap met occult/religieuze inslag van filantropen en verlichte zielen. Lidmaatschap is strikt geheim en kostelijk. Buitenstaanders kijken met veel argwaan naar deze sociëteit. Als jouw betrokkenheid met de vrijmetselaars ooit publiek zou worden, kan dat ernstige en permanente gevolgen hebben voor jouw sociaal aanzien. Deze lobbygroep kan invloed uitoefenen op politiek en gerechtelijk vlak. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een hogere rang te bekleden binnen het gezelschap.'),
  ('Codex Dei', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 1, -50, NULL, 0, 'Een conservatieve prelatuur van zowel leken als gewijden die zich inzet voor kerkelijke waarde en normen. Ze hebben goede contacten met de hoogste regionen van de kerk. De Codex Dei zet zich intensief in voor goede doelen. Deze lobbygroep kan invloed uitoefenen op de kerk. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om meer invloed binnen de vereniging te kunnen uitoefenen.'),
  ('Eredoctoraat', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 1, -50, NULL, 0, 'Jouw familie is al lang een belangrijke geldschieter van een universiteit of je hebt iets gedaan van wetenschappelijk belang. In ruil daarvoor heb jij een eredoctoraat gekregen. Door deze status kan je invloed uitoefenen in academische milieus. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om meer invloed binnen de vereniging te kunnen uitoefenen.'),
  ('GESAA', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 2, -50, NULL, 0, 'Het Gezelschap van Exploratie en Studie van de Archeologie en Antropologie is een sociëteit voor ontdekkingsreizigers en avonturiers. De bovenklasse is graag geldschieter voor deze onbevreesde archeologen die mysterieuze kunstschatten en bloedstollende verhalen meebrengen waarmee zij hun soirees kunnen opluisteren. Door deze status kan je invloed uitoefenen om zaken gedaan te krijgen in de wereld van archeologen en ontdekkingsreizigers. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om meer invloed binnen de vereniging te kunnen uitoefenen.'),
  ('Kunstpatronage', 'upper class', 'status', 1, 'range_positive', 'Mecenaten en sociëteiten', 2, -50, NULL, 0, 'Jouw familie geeft aanzienlijke sommen geld uit aan kunstenaars en musea. Je staat bekend als promotor van goede smaak en cultuur. Door deze status kan je invloed uitoefenen in de culturele sector. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om meer invloed binnen de vereniging te kunnen uitoefenen.'),
  ('Luitenant', 'upper class', 'status', 1, 'range_signed', 'Militair', 1, 240, 0.1, 0, 'Een officier en plaatsvervanger van een kapitein.'),
  ('Kapitein', 'upper class', 'status', 1, 'range_signed', 'Militair', 2, 310, 0.1, 0, 'Officier en de bevelhebber van een militaire eenheid. De kapitein is een officier en wordt bijgestaan door één of twee plaatsvervangende officieren, de luitenanten.'),
  ('Majoor', 'upper class', 'status', 1, 'range_signed', 'Militair', 3, 400, 0.1, 1, 'Een hoofdofficier. Majoors kunnen vele functies binnen defensie vullen. Een belangrijke operationele functie, en vaak hoogtepunt in een militaire carrière, is die van compagniescommandant, een eenheid van ongeveer 100 tot 250 man die vaak zelfstandig opereert. Bij de marine kan een majoor commandant zijn van schepen of luchtschepen. Op de middelgrote schepen en luchtschepen zijn de eerste officier en hoofden van dienst allen majoor.'),
  ('Kolonel', 'upper class', 'status', 1, 'range_signed', 'Militair', 4, 550, 0.1, 1, 'Een hoofdofficier. Een kolonel heeft de leiding over een colonne of regiment (een verzameling eenheden van meestal hetzelfde wapen) of een middelgroot tot groot schip of luchtschip.'),
  ('Generaal', 'upper class', 'status', 1, 'range_signed', 'Militair', 5, 800, 0.1, 2, 'Generaals zijn commanderende officieren van grotere formaties. Deze formaties zijn samengesteld uit eenheden van diverse wapens, zoals infanterie, cavalerie, artillerie, genie en verbindingsdienst, en dienstvakken, zoals de technische dienst. De formaties heten, in aflopende grootte: leger, legerkorps, divisie en brigade. Een leger wordt gecommandeerd door een generaal, een legerkorps door een luitenant-generaal, een divisie door een generaal-majoor en een brigade door een brigade-generaal.'),
  ('Duelleervergunning', 'upper class', 'status', 1, 'singular', 'Persoonlijke bezittingen', 0, NULL, NULL, 0, 'Klein vuurwapen zonder magazijn, met duelleervergunning.'),
  ('Speciale technologie', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 1, NULL, NULL, 0, 'Je bezit een technologisch toestel dat niet zomaar in de winkels te verkrijgen is.'),
  ('Wapenvergunning', 'upper class', 'status', 1, 'singular', 'Persoonlijke bezittingen', 2, -30, NULL, 0, 'Vuurwapen met vergunning tot wapendracht.'),
  ('Luxevoertuig', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 2, -50, NULL, 0, 'Je bezit een klein jacht of luxueuze auto die klaar staat om jou te brengen waar je heen wil. Indien gewenst is een chauffeur inbegrepen.'),
  ('Uitzonderlijke technologie', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 3, -25, NULL, 0, 'Je bezit een heel bijzonder technologisch toestel dat heel zeldzaam is.'),
  ('Boekenverzamelaar', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 3, -75, NULL, 0, 'Je bezit een uitgebreide bibliotheek met een aantal uitzonderlijke, zeldzame boeken. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een grotere boekencollectie te bezitten.'),
  ('Beroemde juwelencollectie', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 4, -125, NULL, 0, 'Je bezit een unieke juwelencollectie waar andere adellijke families jaloers op zijn. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een grotere juwelencollectie te bezitten.'),
  ('Beroemde kunstcollectie', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 4, -75, NULL, 0, 'Je bent een verzamelaar van kunst en hebt in je leven een collectie samengesteld van hoge kwaliteit en bekendheid. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een grotere kunstcollectie te bezitten.'),
  ('Unieke technologie', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 4, -50, NULL, 0, 'Je bezit een uniek en zeer vernuftig technologisch toestel.'),
  ('Transportvoertuig', 'upper class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 5, -200, NULL, 0, 'Je bezit een groot jacht of luxe luchtschip om jou en je gezelschap te vervoeren naar waar je wil. De bemanning is inclusief.'),
  ('Senator', 'upper class', 'status', 1, 'range_signed', 'Politiek', 2, 100, 0.1, 0, 'Je mag zetelen in de senaat. Als je hertog bent, zetel je gratis in de senaat en moet je niet verkozen worden.'),
  ('Schepen', 'upper class', 'status', 1, 'range_signed', 'Politiek', 2, 50, 0.1, 0, 'Je mag zetelen in het schepencollege van een stad en zo mee het beleid bepalen op regionaal niveau.'),
  ('Burgemeester', 'upper class', 'status', 1, 'range_signed', 'Politiek', 4, 160, 0.1, 2, 'Als je niet de burgemeester van Raetsburg bent, moet je zelf een verklaring vinden waarom je zo vaak in Raetsburg komt. Er kan uiteraard maar 1 burgemeester van Raetsburg zijn.'),
  ('Minister of staatssecretaris', 'upper class', 'status', 1, 'range_signed', 'Politiek', 4, 460, 0.1, 2, 'Je maakt deel uit van de ministerraad en opereert dus op nationaal niveau. Je moet zelf een verklaring vinden waarom je zo vaak in Raetsburg komt. Inkomsten: 250Fr.'),
  ('Ambassadeur', 'upper class', 'status', 1, 'range_signed', 'Politiek', 4, 220, 0.1, 1, 'Je bent een edelman uit een vreemd land die in België als ambassadeur van jouw land optreedt. Je moet zelf een verklaring vinden waarom je zo vaak in Raetsburg komt. Inkomsten: 220Fr.'),
  ('Adellijk bloed', 'middle class', 'status', 1, 'singular', 'Achtergrond', 1, NULL, NULL, 0, 'Je hebt blauw bloed door jouw aderen stromen maar om één of andere reden loop je daar niet mee te koop. Misschien weet je niet wie jouw ouders zijn of misschien ben je een bastaard. Het kan ook zijn dat je op de vlucht bent voor een beschamende gebeurtenis of dat je incognito een nieuw leven hebt opgebouwd. Zodra de ware aard van jouw afkomst opnieuw aanvaard wordt, kan je terug bovenklasse worden, maar tot die tijd leef je als een middenklasse burger.'),
  ('Referenties', 'middle class', 'status', 1, 'singular', 'Achtergrond', 1, NULL, NULL, 0, 'Je hebt voor het spel begon reeds goed werk geleverd voor bekende of beruchte mensen. Dit geeft jouw professionele bekwaamheid meer geloofwaardigheid. Referenties moeten in jouw achtergrond opgenomen zijn.'),
  ('Wijding', 'middle class', 'status', 1, 'singular', 'Achtergrond', 1, NULL, NULL, 0, 'Je moet niet rechtstreeks voor de kerk werken, maar bent wel gewijd tot priester. Priesters die lesgeven of die voor het leger werken, bevinden zich vaak in deze situatie. Hoewel je niet voor de kerk werkt, heb je wel de bevoegdheid om sacramenten toe te dienen.'),
  ('Georganiseerde misdaad', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt banden met één van de gevaarlijkste elementen binnen het misdaadmilieu: de georganiseerde misdaad. Uit jouw achtergrond moet duidelijk blijken wat jouw relatie is met het misdaadkartel van jouw keuze. Heb je al eens beroep gedaan op hun diensten, of ben je zelf een volwaardige medewerker? Kies bij welk misdaadfamilie je gekend bent. Enkele kartels waaruit je kan kiezen zijn de Rathkeale Rovers, de ‘Ndrangheta, de Cosa Nostra, de Penose, Le Milieu en de Bokkenrijders. Als jouw connectie ontdekt wordt door de autoriteiten, kan een langdurige gevangenisstraf het gevolg zijn, wat de facto het einde van jouw personage betekent. Hou daar rekening mee. Deze statuseigenschap geeft je de mogelijkheid om vaardigheden van de categorie crimineel te nemen.'),
  ('GESAA', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Het Gezelschap van Exploratie en Studie van de Archeologie en Antropologie is een sociëteit voor ontdekkingsreizigers en avonturiers. Jij bent zo’n avonturier of ontdekkingsreiziger. Lidmaatschap van het GESAA opent deuren naar fondsen en middelen waar een universiteit alleen maar van kan dromen.'),
  ('Gezellen van Janus', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Een kleine sociëteit die vermaak en vrijetijdsbesteding ondersteunt. Jij bent een artiest die aan deze sociëteit verbonden is. Je moet iets kunnen wat mensen kan vermaken. Mentalisten, illusionisten, operazangers, acteurs, balletdansers... al deze podiumkunsten kunnen een onderkomen vinden onder het symbool van het lachende en huilende masker. De Gezellen hebben vele kleine, geheime theaters waar felbegeerde, exclusieve opvoeringen voor leden plaatsvinden. Alleen de beste artiesten treden er op. Lidmaatschap van de gezellen is geheim, zelfs voor de leden. Iedereen draagt een masker of verhult z’n gezicht op bijeenkomsten en kiest een dramatische schuilnaam voor zichzelf. Alleen de persoon die je ingewijd heeft, kent jouw ware identiteit. De gezellen zijn geen werkgever. Je treedt voor hen op na jouw normale uren.'),
  ('Informanten', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt een netwerk van informanten binnen het misdaadmilieu. Informatie uit het crimineel milieu koop je niet met sociale invloed, maar met geld of gunsten. Soms zijn dat stevige sommen. Als je de informatie die je zoekt niet meteen kan achterhalen, dan kan je informanten vragen te infiltreren in nieuwe milieus. Dat kost uiteraard geld en tijd.'),
  ('Liefdadigheidswerk', 'middle class', 'status', 1, 'range_positive', 'Achtergrond', 2, -30, NULL, 0, 'Via initiatieven als het patronaat, de Codex Dei, de Sint-Vincentiusgenootschappen, of via kleinere privé-initiatieven, werk je mee aan het verbeteren van de leeftoestand van de onderklasse. Deze activiteiten slorpen een aanzienlijk deel van jouw vrije tijd en jouw inkomsten op maar dankzij je inzet kan je invloed uitoefenen in de onderklasse en in de kerk als jouw liefdadigheidswerk een kerkelijk initiatief is.'),
  ('Smokkelaars en helers', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt banden binnen het misdaadmilieu met smokkelaars en helers. Je wordt zelf ook regelmatig gevraagd om pakjes verborgen te houden voor de autoriteiten of om betrokken te zijn bij de smokkel of de verkoop van illegale goederen. Zorg dat in jouw achtergrond duidelijk wordt wat jij smokkelaars en helers te bieden hebt. Als jouw activiteiten ontdekt worden door de autoriteiten, zal een langdurige gevangenisstraf het gevolg zijn, wat de facto het einde van jouw personage betekent. Hou daar rekening mee. Deze statuseigenschap geeft je de mogelijkheid om vaardigheden van de categorie crimineel te nemen.'),
  ('Witteboordencriminaliteit', 'middle class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je maakt deel uit van een groep fraudeurs en oplichters. Jullie verafschuwen geweld, maar dat maakt jullie praktijken niet minder verwerpelijk. Verhoog jouw spaarboekje met 30%. Als jouw frauduleuze praktijken ontdekt worden door de autoriteiten, zal een langdurige gevangenisstraf het gevolg zijn, wat de facto het einde van jouw personage betekent. Hou daar rekening mee. Deze eigenschap geeft je de mogelijkheid om zaken te laten bewegen op vlak van witteboordencriminaliteit.'),
  ('Belangrijke aandeelhouder in een kleine onderneming of expeditie', 'middle class', 'status', 1, 'range_signed', 'Economie', 2, NULL, NULL, 0, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 900Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Vastgoed in een arbeiderswijk', 'middle class', 'status', 1, 'range_signed', 'Economie', 3, 160, 0.05, 0, 'Je bezit vastgoed in een arbeiderswijk van de stad. Alle huurgelden worden integraal op jouw rekening gestort. Dit is een heel veilige belegging.'),
  ('Hoofdaandeelhouder in een kleine onderneming of expeditie', 'middle class', 'status', 1, 'range_signed', 'Economie', 3, NULL, NULL, 0, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 1500Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Spaarder', 'middle class', 'status', 1, 'singular', 'Economie', 3, NULL, NULL, 0, 'Bij de start van het spel begin je met een bedrag op je spaarboekje dat gelijk is aan x150 je inkomsten, i.p.v. x10. Tussen 2 evenementen krijg je x4 je netto inkomsten i.p.v. x3.'),
  ('Belangrijke aandeelhouder in een grote onderneming of expeditie', 'middle class', 'status', 1, 'range_signed', 'Economie', 4, NULL, NULL, 1, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 3000Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
  ('Grootgrondbezitter', 'middle class', 'status', 1, 'range_signed', 'Economie', 5, 360, 0.05, 0, 'Je bezit uitgestrekte landerijen en bossen vol met wild. Boeren huren het land van jou om te bewerken. In de wouden heb jij de jachtrechten. Dit is een heel veilige belegging.'),
  ('Hoofdaandeelhouder in een grote onderneming of expeditie', 'middle class', 'status', 1, 'range_signed', 'Economie', 5, NULL, NULL, 2, 'Jaarlijks wordt er een dividend aan jou uitbetaald, afhankelijk van de winst van je onderneming. Tussen 2 evenementen komt er tussen de 0Fr en 10 000Fr bij op je spaarboekje. Als je tijdens het spel je bedrijf kan helpen winstgevend te zijn, zal de kans groter worden op een hoog dividend.'),
