  ('Ontdekkingsreiziger', 'middle class', 'profession', 1, 'range_signed', 'Wildernis', 2, 180, 0.25, 0, 'Mensen die goed thuis zijn in de natuur.'),
  ('Duelleervergunning', 'middle class', 'status', 1, 'singular', 'Persoonlijke bezittingen', 1, -5, NULL, 0, 'Klein vuurwapen zonder magazijn, met duelleervergunning.'),
  ('Speciale technologie', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 1, NULL, NULL, 0, 'Je bezit een technologisch toestel dat niet zomaar in de winkels te verkrijgen is.'),
  ('Wapenvergunning', 'middle class', 'status', 1, 'singular', 'Persoonlijke bezittingen', 2, -30, NULL, 0, 'Vuurwapen met vergunning tot wapendracht.'),
  ('Luxevoertuig', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 2, -50, NULL, 0, 'Je bezit een klein jacht of luxueuze auto die klaar staat om jou te brengen waar je heen wil. Indien gewenst is een chauffeur inbegrepen.'),
  ('Uitzonderlijke technologie', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 3, -25, NULL, 0, 'Je bezit een heel bijzonder technologisch toestel dat heel zeldzaam is.'),
  ('Boekenverzamelaar', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 3, -75, NULL, 0, 'Je bezit een uitgebreide bibliotheek met een aantal uitzonderlijke, zeldzame boeken. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een grotere boekencollectie te bezitten.'),
  ('Beroemde juwelencollectie', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 4, -125, NULL, 0, 'Je bezit een unieke juwelencollectie waar heel wat adellijke families jaloers op zijn. Je kan deze eigenschap meerdere keren nemen zonder extra punten te betalen om een grotere juwelencollectie te bezitten.'),
  ('Unieke technologie', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 4, -50, NULL, 0, 'Je bezit een uniek en zeer vernuftig technologisch toestel.'),
  ('Transportvoertuig', 'middle class', 'status', 0, 'range_positive', 'Persoonlijke bezittingen', 5, -200, NULL, 0, 'Je bezit een groot jacht of luxe luchtschip om jou en je gezelschap te vervoeren naar waar je wil. De bemanning is inclusief.'),
  ('Adellijk bloed', 'lower class', 'status', 1, 'singular', 'Achtergrond', 1, NULL, NULL, 0, 'Je hebt blauw bloed door jouw aderen stromen maar om één of andere reden loop je daar niet mee te koop. Misschien weet je niet wie jouw ouders zijn of misschien ben je een bastaard. Het kan ook zijn dat je op de vlucht bent voor een beschamende gebeurtenis of dat je incognito een nieuw leven hebt opgebouwd. Zodra de ware aard van jouw afkomst opnieuw aanvaard wordt, kan je terug bovenklasse worden, maar tot die tijd leef je als een onderklasse burger.'),
  ('Referenties', 'lower class', 'status', 1, 'singular', 'Achtergrond', 1, NULL, NULL, 0, 'Je hebt voor het spel begon reeds goed werk geleverd voor bekende of beruchte mensen. Dit geeft jouw professionele bekwaamheid meer geloofwaardigheid. Referenties moeten in jouw achtergrond opgenomen zijn.'),
  ('Igor', 'lower class', 'status', 0, 'range_positive', 'Achtergrond', 2, NULL, NULL, 0, 'Er is op je geëxperimenteerd door een wetenschapper. Je hebt het overleefd, maar je bent niet helemaal menselijk meer. Misschien zijn delen van jouw lichaam vervangen door stoomprotheses, zit er vreemd weefsel in jouw lichaam verwerkt of zijn er experimenten op jouw hersenen uitgevoerd. Het is helemaal aan jou om uit te werken wat er precies gebeurd is. Voorbeelden zijn een arm die is vervangen door een wapen of longen waarmee je een tijdje onder water kan ademen. Je kan deze vaardigheid meerdere keren aankopen.'),
  ('Lezen en schrijven', 'lower class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je bent op heel jonge leeftijd een paar jaar naar school geweest en bent niet langer analfabeet.'),
  ('Smokkelaars en helers', 'lower class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt banden binnen het misdaadmilieu met smokkelaars en helers. Je wordt zelf ook regelmatig gevraagd om pakjes verborgen te houden voor de autoriteiten of om betrokken te zijn bij de smokkel of de verkoop van illegale goederen. Zorg dat in jouw achtergrond duidelijk wordt wat jij smokkelaars en helers te bieden hebt. Als jouw activiteiten ontdekt worden door de autoriteiten, zal een langdurige gevangenisstraf het gevolg zijn, wat de facto het einde van jouw personage betekent. Hou daar rekening mee. Deze statuseigenschap geeft je de mogelijkheid om vaardigheden van de categorie crimineel te nemen.'),
  ('Straatbendes', 'lower class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt banden met straatbendes binnen het misdaadmilieu. Ofwel ken je verschillende bendeleden, ofwel behoor je zelf tot een straatbende. Zorg dat in jouw achtergrond duidelijk wordt wat jij straatbendes te bieden hebt. Als jouw activiteiten ontdekt worden door de autoriteiten, kan een langdurige gevangenisstraf het gevolg zijn, wat de facto het einde van jouw personage betekent. Hou daar rekening mee. Deze eigenschap geeft je de mogelijkheid om zaken te laten gebeuren bij een straatbende.'),
  ('Prostitutie', 'lower class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt banden met het prostitutiemilieu. Misschien ken je verschillende pooiers, of heb je veel gedaan om het lot van prostituees te verbeteren. Zorg dat in jouw achtergrond duidelijk wordt waarom jij gerespecteerd wordt binnen het prostitutiemilieu. Deze eigenschap geeft je de mogelijkheid om zaken te laten gebeuren binnen het prostitutiemilieu.'),
  ('Badawi', 'lower class', 'status', 1, 'singular', 'Achtergrond', 2, NULL, NULL, 0, 'Je hebt goede contacten met de enigmatische Badawi, nomadische zwervers en bannelingen uit moslimlanden die vaak samenhokken in tentenkampen of krottenwijken aan de rand van de stad. Zorg dat in jouw achtergrond duidelijk wordt waarom de Badawi geloven dat je het goed met hen voorhebt. Deze eigenschap geeft je de mogelijkheid om zaken te laten gebeuren binnen Badawi families.'),
  ('Opleiding', 'lower class', 'status', 1, 'singular', 'Achtergrond', 4, NULL, NULL, 0, 'Je bent de zoon of dochter van huispersoneel bij een gegoede familie. Je hebt samen met de kinderen van de heer des huizes een opleiding genoten. Je mag academische vaardigheden nemen.'),
  ('Luck of the Irish', 'all', 'quality', 1, 'range_positive', 'Kwaliteiten', 1, NULL, NULL, 0, 'Het geluk lacht je toe. Als het kantje boordje is hoe een situatie zal uitdraaien, dan zal ze uitdraaien in jouw voordeel. Deze statuseigenschap is alleen van toepassing bij twijfel. De meeste vaardigheidstesten hebben duidelijke regels waar geluk niet bij te pas moet komen. Je kan er ook niet toevallig het juiste loterijnummer mee kiezen of kogels mee ontwijken. De regie bepaalt altijd wanneer Luck of the Irish van toepassing is.'),
  ('Medium', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 2, NULL, NULL, 0, 'Soms denk je de stemmen te horen van overledenen. Je hebt geen controle over deze ‘gave’. Er te veel mee te koop lopen zal je een paria maken in de bijgelovige samenleving van Aether.'),
  ('Paranormale achtergrond', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 2, NULL, NULL, 0, 'Er is iets in je verleden dat je verbindt met het bovennatuurlijke. Je mag zelf suggesties doen wat betreft de aard van deze band, maar de regie behoudt zich het recht om dat te weigeren of zelfs helemaal aan te passen. Met deze kwaliteit leg jij je lot voor een stukje in de handen van de regie.'),
  ('Onversaagde pionier', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 4, NULL, NULL, 0, 'Je hebt al heel wat vreemde dingen gezien in deze wereld. Het is niet gemakkelijk om jou nog van iets te laten opkijken. Confrontaties met het bovennatuurlijke geven je 1 stress minder.'),
  ('Onverzettelijke geest', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 4, NULL, NULL, 0, 'Wanneer de geest van anderen verzinkt in waanzin, beschik jij over een vastberadenheid die er voor zorgt dat je niet breekt onder de druk. 1 keer per evenement mag je een psychische aandoening negeren. Wanneer je geest op het punt staat te breken, ben je enkele minuten helemaal van de kaart. Wanneer je weer bij zinnen komt, blijkt je geest ongebroken. Je kiest zelf wanneer je deze kwaliteit gebruikt. Je mag eerst het effect van de psychische aandoening lezen. Na gebruik van deze kwaliteit ga je een nieuw kaartje met een psychische aandoening halen voor het geval je weer stress zou krijgen.'),
  ('Spijkerhard', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 4, NULL, NULL, 0, 'Ze mogen je blijven neerslaan, jij zal steeds weer rechtstaan. 1 keer per evenement mag je een kritieke wonde negeren. Wanneer je kritiek verwond wordt ga je neer en verliest een paar minuten het bewustzijn. Wanneer je weer bijkomt, blijkt het allemaal nog wel mee te vallen. Je kiest zelf wanneer je deze kwaliteit gebruikt. Je mag eerst het effect van de kritieke wonde lezen. Na gebruik van deze kwaliteit ga je een nieuw kaartje met een kritieke wonde halen voor het geval je weer kritiek verwond zou worden.'),
  ('Veteraan', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 4, NULL, NULL, 0, 'Je bent in het verleden betrokken geweest bij gewelddadige conflicten of bloederige situaties. Hierdoor ben je mentaal beter voorbereid op menselijk conflict en strijd. Je krijgt 1 stress minder van menselijke conflicten, geweld en moord.'),
  ('Arcane nexus', 'all', 'quality', 1, 'singular', 'Kwaliteiten', 6, NULL, NULL, 0, 'Hogere machten hebben hun oog op je laten vallen. Bij de creatie van je personage heb je geen idee wat er gaande is. Je hebt geen enkele controle over de richting die arcane nexus zal uitgaan. Kiezen voor deze kwaliteit houdt in dat je regelmatig betrokken zal raken bij situaties waar je weinig of geen controle over hebt.'),
  ('Roem', 'all', 'status', 0, 'range_signed', 'Achtergrond', 2, NULL, 0.1, 0, 'Er is iets gebeurd in jouw verleden waardoor je heel veel media aandacht gekregen hebt. Die aandacht is blijven hangen. Alles wat je doet is groot nieuws. Speel dit uit. Als je op evenementen op de achtergrond blijft en de schijnwerpers vermijdt, dan kan de regie jouw roem doen uitdoven. Indien roem negatief wordt, ben je berucht.');
